# Multiplayer Text RPG — Step 5: Command Parser
# Parse player text input into structured game commands.

import os
import json
import re
from dataclasses import dataclass, field


class GameConfig:
    def __init__(self, config: dict):
        self._config = config
        os.makedirs(config.get('data_dir', 'data'), exist_ok=True)

    def get(self, key: str):
        return self._config.get(key)


@dataclass
class Room:
    name: str = ''
    description: str = ''
    exits: dict = field(default_factory=dict)
    items: list = field(default_factory=list)


class WorldLoader:
    def load_world(self, filepath: str) -> dict:
        with open(filepath) as f:
            raw = json.load(f)
        rooms = {}
        for name, data in raw.items():
            rooms[name] = Room(
                name=name,
                description=data['description'],
                exits=data.get('exits', {}),
                items=data.get('items', [])
            )
        return rooms


def save_world(rooms: dict, filepath: str) -> None:
    data = {}
    for name, room in rooms.items():
        data[name] = {
            'description': room.description,
            'exits': room.exits,
            'items': list(room.items)
        }
    with open(filepath, 'w') as f:
        json.dump(data, f, indent=2)


class GameWorld:
    def __init__(self):
        self._rooms = {}

    def add_room(self, room: Room) -> None:
        self._rooms[room.name] = room

    def get_room(self, name: str):
        return self._rooms.get(name)

    def get_exits(self, room_name: str) -> dict:
        room = self._rooms.get(room_name)
        return room.exits if room else {}


class Player:
    def __init__(self, name: str, current_room: str, health: int = 100,
                 inventory: list = None, gold: int = 0):
        self.name = name
        self.current_room = current_room
        self.health = health
        self.inventory = inventory or []
        self.gold = gold


def move_player(game_world: GameWorld, player: Player, direction: str) -> bool:
    exits = game_world.get_exits(player.current_room)
    if direction in exits:
        player.current_room = exits[direction]
        return True
    return False


class Item:
    def __init__(self, name: str, item_type: str, value: int, description: str):
        self.name = name
        self.item_type = item_type
        self.value = value
        self.description = description


class Inventory:
    def __init__(self):
        self._items = []

    def add(self, item: Item) -> None:
        self._items.append(item)

    def remove(self, name: str) -> bool:
        for item in self._items:
            if item.name == name:
                self._items.remove(item)
                return True
        return False

    def find(self, name: str):
        for item in self._items:
            if item.name == name:
                return item
        return None

    def list_items(self) -> list:
        return list(self._items)

    def total_value(self) -> int:
        return sum(item.value for item in self._items)


class ItemDatabase:
    def __init__(self):
        self._items = {}

    def register(self, item: Item) -> None:
        self._items[item.name] = item

    def get(self, name: str):
        return self._items.get(name)

    def all_items(self) -> list:
        return list(self._items.values())


